#include <bits/stdc++.h>using namespace std;const int N = 55;int t, n, cnt, p[N];bool flag, f[N];void dfs(int step){    if(cnt >= n) return;    if(step > n){        if(cnt < n){            for(int i = 1; i <= n; i++)                cout << p[i] << ' ';            cout << '\n';            cnt++;        }        return;    }    for(int i = 1; i <= n; i++)        if(!f[i] && (step <= 2 || p[step - 2] + p[step - 1] != i)){            f[i] = true;            p[step] = i;            dfs(step + 1);            f[i] = false;        }}void solve(){    cin >> n;    flag = false;    cnt = 0;    dfs(1);}int main(){    cin >> t;    while(t--) solve();    return 0;}